}));

jest.mock('~/constants/functions', () => ({
  eventModalView: jest.fn(),
  eventSelectContent: jest.fn(),
}));

jest.mock('../../../src/services/moment', () => ({
  moment: jest.fn((date: string) => {
    const mockMoment = {
      format: jest.fn((format: string) => {
        if (format === 'DD') return '15';
