import React from 'react';
import { StatusBar as Status } from 'react-native';

import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { useTheme } from 'styled-components/native';

import theme from '../../../styles/theme';

import { useColors } from '../../../hooks';
import { Box } from '../Box';
import { ALLOWED_BG_COLORS, PropsStatusBar } from './Models';

function StatusBar({ bgColor = 'BRAND_BASE_01' }: PropsStatusBar) {
  const { colors } = useTheme() || theme;
  const insets = useSafeAreaInsets();
  const allowedBgColor = useColors(ALLOWED_BG_COLORS);

  return (
    <>
      <Box
        height={insets.top}
        bgColor={allowedBgColor(bgColor)}
        position="absolute"
        width="100%"
      />
      <Status
        backgroundColor={colors[allowedBgColor(bgColor)]}
        barStyle={
          bgColor === 'BRAND_BASE_01' || bgColor === 'BRAND_COMPLEMENT_01'
            ? 'light-content'
            : 'dark-content'
        }
      />
    </>
  );
}

export default StatusBar;

