describe('PointsDetailView', () => {
  const mockHandleGoBack = jest.fn();
  const mockHandleOpenReportProblem = jest.fn(() => {
    mockModalizeRef.current?.open?.();
  });
  const mockHandleCloseReportProblem = jest.fn(() => {
    mockModalizeRef.current?.close?.();
  });
  const mockTransaction: PointsDetailProps['transaction'] = {
    id: '1',
    date: '2024-01-15T10:30:00Z',
    description: 'Test Transaction',
    type: 'CREDIT',
    amount: 1000,
    currencyValue: 50.0,
    icon: 'icon-test',
    details: {
      provider: 'test-provider',
      extraInfo: 'test info',
      fields: [
        {
          label: 'Marca',
          value: 'Toyota',
        },
        {
          label: 'Modelo',
          value: 'Corolla',
        },
        {
          label: 'Placa',
          value: 'ABC-1234',
        },
      ],
    },
  };

  const defaultProps: PointsDetailProps = {
    handleGoBack: mockHandleGoBack,
    transaction: mockTransaction,
    modalizeRef: mockModalizeRef as any,
    handleOpenReportProblem: mockHandleOpenReportProblem,
    handleCloseReportProblem: mockHandleCloseReportProblem,
  };

  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should render component with transaction data', () => {
    const { getByText } = render(
      <TestProvider>
        <PointsDetailView {...defaultProps} />
      </TestProvider>,
    );

    expect(getByText('Test Transaction')).toBeTruthy();
    expect(getByText(/\+ 1\.000/)).toBeTruthy();
  });

  it('should display formatted currency value', () => {
    const { getByText } = render(
      <TestProvider>
        <PointsDetailView {...defaultProps} />
      </TestProvider>,
    );

    expect(getByText('R$ 50,00')).toBeTruthy();
  });

  it('should display formatted date in highlight text', () => {
    const { getByText } = render(
      <TestProvider>
        <PointsDetailView {...defaultProps} />
      </TestProvider>,
    );

    expect(getByText(/Compra feita em/)).toBeTruthy();
  });

  it('should show negative points for DEBIT type', () => {
    const debitTransaction = {
      ...mockTransaction,
      type: 'DEBIT' as const,
      amount: 500,
    };

    const { getByText } = render(
      <TestProvider>
        <PointsDetailView {...defaultProps} transaction={debitTransaction} />
      </TestProvider>,
    );

    expect(getByText(/- 500/)).toBeTruthy();
  });

  it('should show tag content when gainType is TAG', () => {
    const tagTransaction = {
      ...mockTransaction,
      icon: 'icon-tag',
      description: 'Pedágio',
    };

    const { getByText } = render(
      <TestProvider>
        <PointsDetailView {...defaultProps} transaction={tagTransaction} />
      </TestProvider>,
    );

    expect(getByText('Tag')).toBeTruthy();
    expect(getByText('Tipo de compra')).toBeTruthy();
  });

  it('should open modal when "Relatar Problema" button is pressed', () => {
    const { getByText } = render(
      <TestProvider>
        <PointsDetailView {...defaultProps} />
      </TestProvider>,
    );

    const reportButton = getByText('Relatar Problema');
    fireEvent.press(reportButton);

    expect(mockHandleOpenReportProblem).toHaveBeenCalled();
  });

  it('should open phone link when "Capitais" card is pressed', async () => {
    const { eventSelectContent } = require('~/constants/functions');

    const { getByText } = render(
      <TestProvider>
        <PointsDetailView {...defaultProps} />
      </TestProvider>,
    );

    await waitFor(() => {
      const capitasCard = getByText('Capitais');
      fireEvent.press(capitasCard);

      expect(eventSelectContent).toHaveBeenCalledWith({
        content_type: 'cta',
        content_id: 'telefones_capitais',
        location_1: 'monetizacao',
        location_2: 'hub_recompensas_spmais',
        location_3: 'contato_telefones',
      });

      expect(Linking.openURL).toHaveBeenCalledWith('tel:40021552');
    });
  });

  it('should open phone link when "Demais localidades" card is pressed', async () => {
    const { eventSelectContent } = require('~/constants/functions');

    const { getByText } = render(
      <TestProvider>
        <PointsDetailView {...defaultProps} />
      </TestProvider>,
    );

    await waitFor(() => {
      const demaisCard = getByText('Demais localidades');
      fireEvent.press(demaisCard);

      expect(eventSelectContent).toHaveBeenCalledWith({
        content_type: 'cta',
        content_id: 'telefones_demais_localidades',
        location_1: 'monetizacao',
        location_2: 'hub_recompensas_spmais',
        location_3: 'contato_telefones',
      });

      expect(Linking.openURL).toHaveBeenCalledWith('tel:08000150252');
    });
  });

  it('should close modal when "Fechar" is pressed', async () => {
    const { getByText } = render(
      <TestProvider>
        <PointsDetailView {...defaultProps} />
      </TestProvider>,
    );

    await waitFor(() => {
      const closeButton = getByText('Fechar');
      fireEvent.press(closeButton);
      expect(mockHandleCloseReportProblem).toHaveBeenCalled();
    });
  });

  it('should handle REFUNDED transaction type correctly', () => {
    const refundedTransaction = {
      ...mockTransaction,
      type: 'REFUNDED' as const,
      amount: 2000,
    };

    const { getByText } = render(
      <TestProvider>
        <PointsDetailView
          {...defaultProps}
          transaction={refundedTransaction}
        />
      </TestProvider>,
    );

    expect(getByText(/\+ 2\.000/)).toBeTruthy();
  });

  it('should handle transaction without description', () => {
    const transactionWithoutDescription = {
      ...mockTransaction,
      description: '',
    };

    const { queryByText } = render(
      <TestProvider>
        <PointsDetailView
          {...defaultProps}
          transaction={transactionWithoutDescription}
        />
      </TestProvider>,
    );

    expect(queryByText('Test Transaction')).toBeFalsy();
  });
});
